from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Any

from noosphere.models import Conclusion, ReviewReport


@dataclass
class BiasProfile:
    name: str
    prior: str
    known_blindspots: list[str] = field(default_factory=list)


class Reviewer(ABC):
    name: str
    bias_profile: BiasProfile

    @abstractmethod
    def review(self, conclusion: Conclusion, context: dict[str, Any]) -> ReviewReport:
        ...

from __future__ import annotations

from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from noosphere.peer_review.reviewer import Reviewer

_REVIEWERS: dict[str, type[Reviewer]] = {}


def register(cls: type[Reviewer]) -> type[Reviewer]:
    _REVIEWERS[cls.name] = cls
    return cls


def all_reviewers() -> list[type[Reviewer]]:
    return list(_REVIEWERS.values())

from __future__ import annotations

import logging
from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import Any

from noosphere.models import Conclusion, ReviewReport, SwarmReport
from noosphere.peer_review.reviewer import Reviewer
from noosphere.peer_review.reviewers import all_reviewers
from noosphere.store import Store

logger = logging.getLogger(__name__)


class SwarmOrchestrator:
    def __init__(self, store: Store) -> None:
        self._store = store

    def run(
        self,
        conclusion_id: str,
        *,
        context: dict[str, Any] | None = None,
    ) -> SwarmReport:
        conclusion = self._store.get_conclusion(conclusion_id)
        if conclusion is None:
            raise ValueError(f"Conclusion {conclusion_id} not found")

        reviewers: list[Reviewer] = [cls() for cls in all_reviewers()]
        ctx = context or {}
        reports = self._run_reviews(reviewers, conclusion, ctx)

        for report in reports:
            self._store.insert_review_report(report)

        return SwarmReport(
            conclusion_id=conclusion_id,
            reviews=reports,
            rebuttals=[],
        )

    def _run_reviews(
        self,
        reviewers: list[Reviewer],
        conclusion: Conclusion,
        context: dict[str, Any],
    ) -> list[ReviewReport]:
        reports: list[ReviewReport] = []
        with ThreadPoolExecutor() as executor:
            futures = {
                executor.submit(r.review, conclusion, context): r
                for r in reviewers
            }
            for future in as_completed(futures):
                reviewer = futures[future]
                try:
                    reports.append(future.result())
                except Exception:
                    logger.exception("Reviewer %s failed", reviewer.name)
        return reports

from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")

